#include <bits/stdc++.h>
using namespace std;
long long gcd(long long a,long long b){
	if(b==0)return a;
	return gcd(b,a%b);
}
void Write(long long a,long long b){
	long long p=a,q=b;
	long long g=gcd(abs(a),abs(b));
	p/=g,q/=g;
	if(q<0)p=-p,q=-q;
	if(q==1)cout<<p;
	else cout<<p<<'/'<<q;
}
int main(){
    long long t,m;
    cin>>t>>m;
    while(t--){
    	long long a,b,c,d;
    	cin>>a>>b>>c;
    	d=b*b-4*a*c;
    	if(d<0)cout<<"NO\n";
		else if(int(sqrt(d))*int(sqrt(d))==d){
			int p;
			if(((-b)+sqrt(d))/2/a>((-b)-sqrt(d))/2/a)p=(-b)+sqrt(d);
			else p=(-b)-sqrt(d);
			long long q=2*a;
			Write(p,q);
			cout<<'\n';
		}else{
			long long q1s=-b,q1m=2*a,q2s,q2m=2*abs(a);
			if(q1s!=0){
				Write(q1s,q1m);
				cout<<'+';
			}
			for(int i=sqrt(d);i;i--)
				if(d%(i*i)==0){
					d/=i*i;
					q2s=i;
					break;
				}
			int g=gcd(q2s,q2m);//cout<<q2s<<'/'<<q2m<<endl;
			q2s/=g,q2m/=g;
			if(q2s==q2m)cout<<"sqrt("<<d<<")\n";
			else if(q2m==1)cout<<q2s<<"*sqrt("<<d<<")\n";
			else if(q2s==1)cout<<"sqrt("<<d<<")/"<<q2m<<'\n';
			else cout<<q2s<<"*sqrt("<<d<<")/"<<q2m<<'\n';
		}
	}
    return 0;
}
